internal class WrappingRuleLambdaParameterListMaxLineLengthTest {
    private val wrappingRuleAssertThat = assertThatRule { WrappingRule() }

    @Test
    fun `Wrap lambda exceeding max line length by inserting newline after arrow instead of after lbrace`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                                                   $EOL_CHAR
            fun foooooooooooooooooooooooooooooooooooooooooooooooooooooo(block: (Int) -> Unit) {}
            fun bar() {
                foooooooooooooooooooooooooooooooooooooooooooooooooooooo { size -> doSomethingWithAReallyLongName(size) }
            }
            fun doSomethingWithAReallyLongName(size: Int) {}
            """.trimIndent()
        val formattedCode =
            """
            // $MAX_LINE_LENGTH_MARKER                                                   $EOL_CHAR
            fun foooooooooooooooooooooooooooooooooooooooooooooooooooooo(block: (Int) -> Unit) {}
            fun bar() {
                foooooooooooooooooooooooooooooooooooooooooooooooooooooo { size ->
                    doSomethingWithAReallyLongName(size)
                }
            }
            fun doSomethingWithAReallyLongName(size: Int) {}
            """.trimIndent()

        wrappingRuleAssertThat(code)
            .setMaxLineLength()
            .addAdditionalRuleProvider { IndentationRule() }
            .isFormattedAs(formattedCode)
    }
}
"}

