147→    private fun beforeVisitBlock(
148→        node: ASTNode,
149→        autoCorrect: Boolean,
150→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
151→    ) {
152→        require(node.elementType == BLOCK)
153→
154→        val lbrace =
155→            node
156→                .getStartOfBlock()
157→                ?.takeIf { it.elementType == LBRACE }
158→                ?: return
159→        if (lbrace.followedByNewline() ||
160→            lbrace.followedByEolComment() ||
161→            lbrace.isPartOf(LONG_STRING_TEMPLATE_ENTRY)
162→        ) {
163→            // String template inside raw string literal may exceed the maximum line length
164→            return
165→        }
166→
167→        val arrowInFunctionLiteralOnSameLineAsLbrace =
168→            lbrace
169→                .treeParent
170→                .takeIf { it.elementType == FUNCTION_LITERAL }
171→                ?.findChildByType(ARROW)
172→                ?.takeIf { noNewLineInClosedRange(lbrace, it) }
173→
174→        node
175→            .takeUnless { it.firstChildLeafOrSelf().elementType == EOL_COMMENT }
176→            ?.getEndOfBlock()
177→            ?.takeIf { it.elementType == RBRACE }
178→            ?.let { rbrace ->
179→                if (
180→                    hasNewLineInClosedRange(lbrace, rbrace) &&
181→                    arrowInFunctionLiteralOnSameLineAsLbrace == null
182→                ) {
183→                    requireNewlineAfterLeaf(lbrace, autoCorrect, emit)
184→                }
185→            }
186→
187→        if (maxLineLength != MAX_LINE_LENGTH_PROPERTY_OFF) {
188→            val lengthUntilBeginOfLine =
189→                node
190→                    .leaves(false)
191→                    .takeWhile { !it.isWhiteSpaceWithNewline() }
192→                    .sumOf { it.textLength }
193→            val lengthUntilEndOfLine =
194→                node
195→                    .firstChildLeafOrSelf()
196→                    .leavesIncludingSelf()
197→                    .takeWhile { !it.isWhiteSpaceWithNewline() }
198→                    .sumOf { it.textLength }
199→            if (lengthUntilBeginOfLine + lengthUntilEndOfLine > maxLineLength) {
200→                if (arrowInFunctionLiteralOnSameLineAsLbrace != null) {
201→                    requireNewlineAfterLeaf(arrowInFunctionLiteralOnSameLineAsLbrace, autoCorrect, emit)
202→                } else {
203→                    requireNewlineAfterLeaf(lbrace, autoCorrect, emit)
204→                }
205→            }
206→        }
207→    }
208→
209→    private fun ASTNode.followedByEolComment() =
210→        null !=
211→            leaves()
212→                .takeWhile { it.isWhiteSpaceWithoutNewline() || it.elementType == EOL_COMMENT }
213→                .firstOrNull { it.elementType == EOL_COMMENT }
